
const nodejs = `
// npm install crypto-js -s 
// npm install axios -s 
// npm install json-bigint -s 
import CryptoJS from "crypto-js";
import axios from "axios";
import JSONBig from "json-bigint";
const API_KEY = ""
const API_SECRET = ""
const HOST = "HHOOSSTT"
const API = AAPPII
async function main() {
    await bingXOpenApiTest(API.protocol, HOST, API.uri, API.method, API_KEY, API_SECRET)
}
function getParameters(API, timestamp, urlEncode) {
    let paramsObj = {}
    if (API.payload) {
        for (const key in API.payload) {
            paramsObj[key] = API.payload[key]
        }
    }
    paramsObj['timestamp'] = timestamp
    
    const sortedKeys = Object.keys(paramsObj).sort()
    
    let parameters = ""
    for (let i = 0; i < sortedKeys.length; i++) {
        if (i > 0) {
            parameters += "&"
        }
        const key = sortedKeys[i]
        let value = paramsObj[key]
        
        if (urlEncode) {
            value = encodeURIComponent(value)
        }
        parameters += key + "=" + value
    }
    return parameters
}

main().catch(console.err);
async function bingXOpenApiTest(protocol, host, path, method, API_KEY, API_SECRET) {
    const timestamp = new Date().getTime()
    const paramsStr = getParameters(API, timestamp, false)
    const sign = CryptoJS.enc.Hex.stringify(CryptoJS.HmacSHA256(paramsStr, API_SECRET))
    console.log("sign=" + sign)
    const url = protocol+"://"+host+path+"?"+getParameters(API, timestamp, true)+"&signature="+sign
    console.log(url)
    const config = {
        method: method,
        url: url,
        headers: {
            'X-BX-APIKEY': API_KEY,
        },
        transformResponse: [(data) => {
            return JSONBig({ storeAsString: true }).parse(data);
        }]
    };
    const resp = await axios(config);
    console.log("demo:", JSON.stringify(resp.data));
}`
export default nodejs




