<template>
  <div class="api-path-copy-container">
    <div class="api-path-copy" @click="copyPath">
      <span class="api-method">{{ method }}</span>
      <span class="api-path">{{ path }}</span>

      <span v-if="title" class="api-title">({{ title }})</span>

      <span class="api-copy-label">{{ copyLabel }}</span>
    </div>
  </div>
</template>

<script>
export default {
  name: 'CopyPath',
  props: {
    method: String,
    path: String,
    title: String
  },
  computed: {
    copyLabel() {
      return this.$store.state.lang === '繁体中文' ? '複製' : 'Copy'
    },
    copiedText() {
      return this.$store.state.lang === '繁体中文'
          ? '已複製到剪貼簿'
          : 'Copied to clipboard'
    }
  },
  methods: {
    async copyPath() {
      try {
        await navigator.clipboard.writeText(`${this.method} ${this.path}`)
        this.$message.success(this.copiedText)
      } catch (_) {
        // fallback for older browsers
        const input = document.createElement('input')
        input.value = `${this.method} ${this.path}`
        document.body.appendChild(input)
        input.select()
        document.execCommand('copy')
        input.remove()
        this.$message.success(this.copiedText)
      }
    }
  }
}
</script>

<style scoped>
.api-path-copy-container {
  margin: 8px 0 12px;
}

.api-path-copy {
  display: flex;
  align-items: center;
  font-size: 13px;
  color: #303133;
  cursor: pointer;
  flex: 1;
}

/* method 做成小绿标签，和你截图风格一致 */
.api-method {
  font-weight: 600;
  font-size: 12px;
  color: #67c23a;
  background: #f0f9eb;
  border-radius: 2px;
  padding: 2px 6px;
  margin-right: 8px;
}

.api-path {
  font-family: Menlo, Monaco, Consolas, monospace;
}

.api-title {
  margin-left: 6px;
  color: #606266;
}

/* 复制按钮变成小胶囊，贴在右边但不过分抢眼 */
.api-copy-label {
  margin-left: 12px;           /* 紧跟在标题后 */
  font-size: 12px;
  color: #909399;
  padding: 2px 8px;
  border-radius: 10px;
  border: 1px solid transparent;
  transition: all 0.15s ease;
}

.api-path-copy:hover .api-copy-label {
  border-color: #dcdfe6;
  background: #f5f7fa;
  color: #409eff;
}

</style>



