const cURL = `
# apt install openssl
# apt install curl

API_KEY=""
API_SECRET=""

TIMESTAMP=$(perl -MTime::HiRes=time -e 'printf("%.0f\\n", time()*1000)')

HOST="HHOOSSTT"
PROTOCOL="PPRROOTTOOCCOOLL"
METHOD="MMEETTHHOODD"
API="AAPPII"

# Build parameters string for signature (excluding timestamp and signature from body)
PARAMETERS='PPAARRAAMMEETTEERRSS'

# remove user-provided timestamp if exists (avoid double timestamp)
PARAMETERS=$(printf "%s" "$PARAMETERS" | perl -pe 's/(^|&)timestamp=[^&]*(&|$)/$1$2/g; s/^&+//; s/&+$//; s/&&+/&/g')

if [ -n "$PARAMETERS" ]; then
  SORTED_LINES=$(printf "%s" "$PARAMETERS" | tr '&' '\\n' | LC_ALL=C sort)
else
  SORTED_LINES=""
fi

if [ -n "$SORTED_LINES" ]; then
  PARAMETERS_SORTED=$(printf "%s" "$SORTED_LINES" | paste -sd '&' -)
  PARAMS_STR="$PARAMETERS_SORTED&timestamp=$TIMESTAMP"
else
  PARAMETERS_SORTED=""
  PARAMS_STR="timestamp=$TIMESTAMP"
fi

sign=^echo -n "$PARAMS_STR" | openssl dgst -sha256 -hmac "$API_SECRET" -hex^
sign=$\{sign##* \}

# Build JSON body with all parameters including timestamp and signature
BODY_PARAMS=""
if [ -n "$PARAMETERS_SORTED" ]; then
  while IFS= read -r part; do
    [ -z "$part" ] && continue
    case "$part" in
      *=*)
        key=\${part%%=*}
        value=\${part#*=}
        # Escape JSON special characters in value
        value=$(printf "%s" "$value" | sed 's/\\\\/\\\\\\\\/g; s/"/\\\\"/g')
        if [ -z "$BODY_PARAMS" ]; then
          BODY_PARAMS="\\"$key\\":\\"$value\\""
        else
          BODY_PARAMS="$BODY_PARAMS,\\"$key\\":\\"$value\\""
        fi
        ;;
    esac
  done <<EOF
$SORTED_LINES
EOF
fi

BODY_JSON="{"
if [ -n "$BODY_PARAMS" ]; then
  BODY_JSON="$BODY_JSON$BODY_PARAMS,"
fi
BODY_JSON="$BODY_JSON\\"timestamp\\":$TIMESTAMP,\\"signature\\":\\"$sign\\""
BODY_JSON="$BODY_JSON}"

curl --globoff --location --request "$METHOD" \
  --header "X-BX-APIKEY: $API_KEY" \
  --header "Content-Type: application/json" \
  --data-raw "$BODY_JSON" \
  "$PROTOCOL://$HOST$API"
`
export default cURL




