const cURL = `
# apt install openssl
# apt install curl

API_KEY=""
API_SECRET=""

TIMESTAMP=$(perl -MTime::HiRes=time -e 'printf("%.0f\\n", time()*1000)')

PARAMETERS='PPAARRAAMMEETTEERRSS'
HOST="HHOOSSTT"
PROTOCOL="PPRROOTTOOCCOOLL"
METHOD="MMEETTHHOODD"
API="AAPPII"

# remove user-provided timestamp if exists (avoid double timestamp)
PARAMETERS=$(printf "%s" "$PARAMETERS" | perl -pe 's/(^|&)timestamp=[^&]*(&|$)/$1$2/g; s/^&+//; s/&+$//; s/&&+/&/g')

if [ -n "$PARAMETERS" ]; then
  SORTED_LINES=$(printf "%s" "$PARAMETERS" | tr '&' '\\n' | LC_ALL=C sort)
else
  SORTED_LINES=""
fi

if [ -n "$SORTED_LINES" ]; then
  PARAMETERS_SORTED=$(printf "%s" "$SORTED_LINES" | paste -sd '&' -)
  PARAMS_STR="$PARAMETERS_SORTED&timestamp=$TIMESTAMP"
else
  PARAMETERS_SORTED=""
  PARAMS_STR="timestamp=$TIMESTAMP"
fi
PARAMETERS="$PARAMS_STR"

NEED_ENCODE=0
printf "%s" "$PARAMETERS" | grep -qE '[\\[\\{]' && NEED_ENCODE=1

url_encode () {
  perl -CS -e '
    use Encode qw(encode_utf8);
    my $s = encode_utf8($ARGV[0]);
    for my $c (unpack("C*", $s)) {
      if (
        ($c>=0x41 && $c<=0x5A) ||
        ($c>=0x61 && $c<=0x7A) ||
        ($c>=0x30 && $c<=0x39) ||
        $c==0x2D || $c==0x2E || $c==0x5F || $c==0x7E
      ) { print chr($c); }
      else { printf("%%%02X", $c); }
    }
  ' "$1"
}

URL_PARAMETERS=""
if [ -n "$PARAMETERS_SORTED" ]; then
  while IFS= read -r part; do
    [ -z "$part" ] && continue
    [ -n "$URL_PARAMETERS" ] && URL_PARAMETERS="$URL_PARAMETERS&"
    case "$part" in
      *=*)
        key=\${part%%=*}
        value=\${part#*=}
        [ $NEED_ENCODE -eq 1 ] && value=$(url_encode "$value")
        URL_PARAMETERS="$URL_PARAMETERS$key=$value"
        ;;
      *)
        URL_PARAMETERS="$URL_PARAMETERS$part"
        ;;
    esac
  done <<EOF
$SORTED_LINES
EOF
fi

if [ -n "$URL_PARAMETERS" ]; then
  URL_PARAMETERS="$URL_PARAMETERS&timestamp=$TIMESTAMP"
else
  URL_PARAMETERS="timestamp=$TIMESTAMP"
fi

sign=^echo -n "$PARAMETERS" | openssl dgst -sha256 -hmac "$API_SECRET" -hex^
sign=$\{sign##* \}

curl --globoff --location --request "$METHOD" \
  --header "X-BX-APIKEY: $API_KEY" \
  "$PROTOCOL://$HOST$API?$URL_PARAMETERS&signature=$sign"
`
export default cURL



