</style>

<script>
import { docs as apiDocs } from '../Docs/index'
import generateCodeJson  from '../utils/ws/generate';
import Prism from 'prismjs'
import 'prismjs/themes/prism.css'

import 'prismjs/components/prism-json'
import 'prismjs/components/prism-python'
import 'prismjs/components/prism-javascript'
import 'prismjs/components/prism-go'
import 'prismjs/components/prism-java'
import 'prismjs/components/prism-bash'

// php 可选
import 'prismjs/components/prism-markup-templating'
import 'prismjs/components/prism-php'


const enDoc = {}
const cnDoc = {}

apiDocs.forEach(menu => {
  menu.list.forEach(subMenub => {
    subMenub.docs.forEach(docObj => {
      if (docObj.pathOri == './概述.json') {
        const keyZH = '/zh-tw/info';
        const keyEN = '/en/info';
        cnDoc[keyZH] = docObj.doc;
        enDoc[keyEN] = docObj.doc;
      } else if (docObj.pathOri == './更新記錄.json') {
        const keyZH = '/zh-tw/changes/logs';
        const keyEN = '/en/changes/logs';
        cnDoc[keyZH] = docObj.doc;
        enDoc[keyEN] = docObj.doc;
      } else {
        // 对 subMenub.en 进行 encodeURIComponent 编码
        const encodedSubMenuEn = encodeURIComponent(subMenub.en);
        const keyZH = '/zh-tw' + '/' + menu.en + '/' + encodedSubMenuEn + '/' + encodeURIComponent(docObj.doc.title);
        const keyEN = '/en' + '/' + menu.en + '/' + encodedSubMenuEn + '/' + encodeURIComponent(docObj.doc.en);
        cnDoc[keyZH] = docObj.doc;
        enDoc[keyEN] = docObj.doc;
      }
    });
  });
});


export default {
  name: 'WebsocketDoc',

  // 不再使用 props.content；改为本地 state
  // props: { content: Object },

  data() {
    return {
      // 当前选中的语言
      activeLang: 'python',
      activeCodeTab: 'json',

      enDoc: {},
      cnDoc: {},

      content: {},

      unsub_payload: '',
      payload: '',
      responseBody: '',
      dataUpdateDemo: '',

      wsRequest: [],
      wsResponse: [],
      errorList: [],

      tableData: [
        { env: 'PROD', address: 'wss://open-api-swap.bingx.com/swap-market' },
        { env: 'VST', address: 'wss://vst-open-api-ws.bingx.com/swap-market' }
      ],
      msgMap: {
        success: {
          '繁体中文': '複製成功',
          'English': 'Copy Successfully'
        },
        error: {
          '繁体中文': '複製失敗',
          'English': 'Copy Failed'
        }
      },
      demoHtml: ''
    }
  },
  methods: {
    normalizeInfoList(info) {
      if (Array.isArray(info)) return info
      if (info == null || info === '') return []
      return [info]
    },
    // Element-UI row-class-name 回调
    tableRowClassName({ row, rowIndex }) {
      return ''
    },

    scrollToElement(tab) {
      this.$nextTick(() => {
        const label = tab && tab.label ? tab.label : ''
        const el = this.$refs[label] || this.$refs[label.toLowerCase()]
        if (el && el.scrollIntoView) {
          el.scrollIntoView({ behavior: 'smooth' })
        }
      })
    },

    normalizeContent(raw) {
      const safe = raw || {}
      // info
      if (!safe.info) safe.info = {}
      if (!Array.isArray(safe.info.zh)) safe.info.zh = []
      if (!Array.isArray(safe.info.en)) safe.info.en = []

      // api
      if (!safe.api) safe.api = {}
      const api = safe.api

      if (!api.request)  api.request  = safe.request  || { list: [], info: '', en: '' }
      if (!api.response) api.response = safe.response || { list: [], info: '', en: '' }
      if (!api.error)    api.error    = safe.error    || { list: [], info: '', en: '' }


      // request - 在根级别，不在 api 下面
      if (!safe.request) safe.request = {}
      if (!Array.isArray(safe.request.list)) safe.request.list = []
      if (typeof safe.request.info !== 'string') safe.request.info = ''
      if (typeof safe.request.en !== 'string') safe.request.en = ''

      // response - 在根级别，不在 api 下面
      if (!safe.response) safe.response = {}
      if (!Array.isArray(safe.response.list)) safe.response.list = []
      if (typeof safe.response.info !== 'string') safe.response.info = ''
      if (typeof safe.response.en !== 'string') safe.response.en = ''

      // error - 在根级别，不在 api 下面
      if (!safe.error) safe.error = {}
      if (!Array.isArray(safe.error.list)) safe.error.list = []
      if (typeof safe.error.info !== 'string') safe.error.info = ''
      if (typeof safe.error.en !== 'string') safe.error.en = ''

      // code/demo 字段统一为字符串，便于 v-html
      const str = v => (typeof v === 'string' ? v : JSON.stringify(v || '', null, 2))
      api.payload = str(api.payload)
      api.unsub_payload = str(api.unsub_payload)
      api.responseBody = str(api.responseBody)

      return safe
    },

    hydrateFromRoute() {
      const path = this.$route.path
      const isZh = path.split('/')[1] === 'zh-tw'
      
      // 尝试直接查找
      let raw = isZh ? this.cnDoc[path] : this.enDoc[path]
      
      // 如果找不到，尝试标准化路径格式：menu.en 不编码，后续段编码
      if (!raw) {
        const pathParts = path.split('/')
        if (pathParts.length >= 3) {
          const attempts = []
          
          // 标准化路径：menu.en 不编码，subMenu.en 和 title 编码
          const normalized = [pathParts[0], pathParts[1]] // 空字符串和语言段
          
          // menu.en 段（索引2）不编码
          if (pathParts.length > 2) {
            let menuEn = pathParts[2]
            try {
              const decoded = decodeURIComponent(menuEn)
              normalized.push(decoded) // menu.en 不编码
            } catch (e) {
              normalized.push(pathParts[2])
            }
          }
          
          // 后续段（subMenu.en 和 title）需要编码
          for (let i = 3; i < pathParts.length; i++) {
            const segment = pathParts[i]
            if (segment) {
              try {
                // 先解码（处理Vue Router可能已解码的情况）
                const decoded = decodeURIComponent(segment)
                // 重新编码，确保格式一致
                normalized.push(encodeURIComponent(decoded))
              } catch (e) {
                // 解码失败，说明可能包含未编码字符，直接编码
                normalized.push(encodeURIComponent(segment))
              }
            } else {
              normalized.push(segment)
            }
          }
          attempts.push(normalized.join('/'))
          
          // 完全编码版本（除了语言段）
          const fullyEncoded = [pathParts[0], pathParts[1]]
          for (let i = 2; i < pathParts.length; i++) {
            let segment = pathParts[i]
            if (segment) {
              try {
                const decoded = decodeURIComponent(segment)
                fullyEncoded.push(encodeURIComponent(decoded))
              } catch (e) {
                fullyEncoded.push(encodeURIComponent(segment))
              }
            } else {
              fullyEncoded.push(segment)
            }
          }
          attempts.push(fullyEncoded.join('/'))
          
          // 尝试所有可能的路径格式
          for (const attemptPath of attempts) {
            raw = isZh ? this.cnDoc[attemptPath] : this.enDoc[attemptPath]
            if (raw) {
              console.log('Found doc with path:', attemptPath)
              break
            }
          }
          
          // 如果还是找不到，尝试遍历所有索引键，找到匹配的文档
          if (!raw) {
            const docMap = isZh ? this.cnDoc : this.enDoc
            for (const [indexPath, indexDoc] of Object.entries(docMap)) {
              // 比较路径的各个段（忽略编码差异）
              const currentParts = path.split('/')
              const indexParts = indexPath.split('/')
              
              if (currentParts.length === indexParts.length) {
                let match = true
                for (let i = 0; i < currentParts.length; i++) {
                  if (i === 0) continue // 跳过空字符串
                  if (i === 1) {
                    // 语言段必须完全匹配
                    if (currentParts[i] !== indexParts[i]) {
                      match = false
                      break
                    }
                  } else {
                    // 其他段：解码后比较
                    try {
                      const currentDecoded = decodeURIComponent(currentParts[i])
                      const indexDecoded = decodeURIComponent(indexParts[i])
                      if (currentDecoded !== indexDecoded) {
                        match = false
                        break
                      }
                    } catch (e) {
                      // 如果解码失败，直接比较
                      if (currentParts[i] !== indexParts[i]) {
                        match = false
                        break
                      }
                    }
                  }
                }
                if (match) {
                  raw = indexDoc
                  console.log('Found doc by path matching:', indexPath)
                  break
                }
              }
            }
          }
        }
      }

      this.content = this.normalizeContent(raw)

      const api = this.content.api || {}

      this.wsRequest =
          api.request && Array.isArray(api.request.list)
              ? api.request.list
              : []

      this.wsResponse =
          api.response && Array.isArray(api.response.list)
              ? api.response.list
              : []

      this.errorList =
          api.error && Array.isArray(api.error.list)
              ? api.error.list
              : []


      // v-html 使用的字符串
      this.payload        = api.payload
      this.unsub_payload  = api.unsub_payload
      this.responseBody   = api.responseBody
      this.dataUpdateDemo = api.dataUpdateDemo
    },
    updateAddressBasedOnRoute(path) {
      let split = path.split('/');
      let businessPart;
      if (split.length >= 3) {
        // 获取业务部分（索引 2，因为 split[0] 是空字符串，split[1] 是语言）
        businessPart = split[2]
        
        // 先解码（处理 URL 编码的情况，如 "Coin-M%20Futures"）
        try {
          businessPart = decodeURIComponent(businessPart)
        } catch (e) {
          // 如果解码失败，使用原始值
        }
        
        // 转换为小写进行比较
        const businessPartLower = businessPart.toLowerCase()
        // 同时检查完整路径（处理中文路径如 "4-币本位"）
        const pathLower = path.toLowerCase()
        
        // 判断路由路径是否包含 swap、spot 或 coin-m futures
        // 使用 includes 来匹配，以处理各种大小写和编码情况
        // 币本位判断要放在 U 本位之前，避免误判
        if (businessPartLower.includes('coin-m') || businessPartLower.includes('cswap') || pathLower.includes('4-币本位') || pathLower.includes('/cswap/')) {
          // Coin-M Futures (币本位合约)
          this.tableData = [
            { env: 'PROD', address: 'wss://open-api-cswap-ws.bingx.com/market' },
            { env: 'VST', address: '' }
          ];
        } else if (businessPartLower.includes('spot') || pathLower.includes('/3-现货/')) {
          // Spot (现货)
          this.tableData = [
            { env: 'PROD', address: 'wss://open-api-ws.bingx.com/market' },
            { env: 'VST', address: '' }
          ];
        } else if (businessPartLower.includes('swap') && !businessPartLower.includes('cswap') && !businessPartLower.includes('coin-m')) {
          // Swap (U本位合约)
          this.tableData = [
            { env: 'PROD', address: 'wss://open-api-swap.bingx.com/swap-market' },
            { env: 'VST', address: 'wss://vst-open-api-ws.bingx.com/swap-market' }
          ];
        }
      }
    },
    // 根据当前语言和 API 数据生成代码
    generateCode() {
      // 确保 this.api 已经传入，并从中获取 uri, method, payload
      const payload = (this.content && this.content.api && this.content.api.payload) || {};
      let payloadObj = payload;
      if (typeof payloadObj === 'string') {
        try {
          payloadObj = JSON.parse(payloadObj);
        } catch (e) {}
        if (typeof payloadObj === 'string') {
          try {
            payloadObj = JSON.parse(payloadObj);
          } catch (e) {}
        }
      }
      let uri = '';
      if (payloadObj) {
        if (typeof payloadObj === 'string') {
          uri = payloadObj.replace(/\\n\\s*/g, '').trim();
        } else {
          uri = JSON.stringify(payloadObj);
        }
      }
      const api = {
        uri,
      };


      // 获取 host 地址
      const host = (this.tableData.find(item => item.env === 'PROD') && this.tableData.find(item => item.env === 'PROD').address) || '';
      // console.log('api',api)
      // console.log('host',host)
      // 使用 generateCodeJson 生成代码，并将其赋值给 payloadHtml
      this.demoHtml = generateCodeJson(api, this.activeLang, host, 'No code available');
      // console.log('demoHtml',this.demoHtml)
      // 使用 nextTick 确保 DOM 更新完成后再设置样式
      this.$nextTick(() => {
        this.resizeAndHighlight(); // 调用样式调整方法
      });
    },
    // 复制成功回调
    onCopy() {
      this.$message.success(this.msgMap['success'][this.$store.state.lang]);  // 显示成功消息
    },

    // 复制失败回调
    onError() {
      this.$message.error(this.msgMap['error'][this.$store.state.lang]);  // 显示错误消息
    },
    resizeAndHighlight() {
      this.$nextTick(() => {
        const targets = [
          // WS: subscribe / ok / update / unsub
          { block: this.$refs.wsSubBlock,    code: this.$refs.wsSubCode,    lang: 'json', raw: this.payloadHtml },
          { block: this.$refs.wsSubOkBlock,  code: this.$refs.wsSubOkCode,  lang: 'json', raw: this.responseBodyHtml },
          {
            block: this.$refs.wsUpdateBlock,
            code: this.$refs.wsUpdateCode,
            lang: 'javascript',
            raw: (this.$store.state.lang === '繁体中文' ? this.dataUpdateDemoJsoncZh : this.dataUpdateDemoJsoncEn)
          },

          { block: this.$refs.wsUnsubBlock,  code: this.$refs.wsUnsubCode,  lang: 'json', raw: this.unsubPayloadHtml },
          { block: this.$refs.wsSubBlockEn,   code: this.$refs.wsSubCodeEn,   lang: 'json', raw: this.payloadHtml },
          { block: this.$refs.wsSubOkBlockEn, code: this.$refs.wsSubOkCodeEn, lang: 'json', raw: this.responseBodyHtml },
          {
            block: this.$refs.wsUpdateBlockEn,
            code: this.$refs.wsUpdateCodeEn,
            lang: 'javascript',
            raw: this.dataUpdateDemoJsoncEn
          },
          { block: this.$refs.wsUnsubBlockEn,  code: this.$refs.wsUnsubCodeEn,  lang: 'json', raw: this.unsubPayloadHtml },
          // generated demo code
          { block: this.$refs.demoBlock,     code: this.$refs.demoCode,     lang: this.prismLang, raw: this.demoHtml },
          { block: this.$refs.demoBlockEn,    code: this.$refs.demoCodeEn,    lang: this.prismLang, raw: this.demoHtml },
        ].filter(t => t.block && t.code)

        targets.forEach(t => {
          t.code.className = `language-${t.lang}`
          t.code.textContent = (t.raw == null ? '' : String(t.raw))
          Prism.highlightElement(t.code)
        })

        setTimeout(() => {
          requestAnimationFrame(() => {
            targets.forEach(t => {
              if (t.block && t.code) {
                t.block.style.height = 'auto'
                t.block.style.height = t.block.scrollHeight + 'px'
              }
            })
          })
        }, 0)
      })
    },

    onLangTabClick(tab) {
      if (tab && tab.name) this.activeLang = tab.name
      this.generateCode()
      this.$nextTick(() => this.resizeAndHighlight())
    },

    // 把 "dataUpdateDemo" 的 JSON（对象或字符串）解析成对象
    safeParseJson(v) {
      if (v == null) return null
      if (typeof v === 'object') return v
      if (typeof v !== 'string') return null
      try { return JSON.parse(v) } catch (e) { return null }
    },

    // 根据 response.list (字段注释表) 自动生成 jsonc
    // lang: 'zh' 或 'en'
    buildJsonc(exampleObj, fieldList, lang = 'en', usePath = false) {
      if (!exampleObj || typeof exampleObj !== 'object') return ''
      const list = Array.isArray(fieldList) ? fieldList : []

      const commentMap = {}
      list.forEach(it => {
        const key = it && it.name
        if (!key) return
        const txt = (lang === 'zh') ? (it.zh || '') : (it.en || '')
        commentMap[key] = String(txt || '')
      })

      const indentUnit = '  '

      const render = (val, level, parentPath) => {
        const indent = indentUnit.repeat(level)

        if (Array.isArray(val)) {
          if (val.length === 0) return '[]'
          const lines = ['[']
          val.forEach((item, idx) => {
            const s = render(item, level + 1, parentPath) // 数组沿用同一路径
            const comma = (idx === val.length - 1) ? '' : ','
            lines.push(`${indent}${indentUnit}${s}${comma}`)
          })
          lines.push(`${indent}]`)
          return lines.join('\n')
        }

        if (val && typeof val === 'object') {
          const keys = Object.keys(val)
          if (keys.length === 0) return '{}'
          const lines = ['{']

          keys.forEach((k, idx) => {
            const v = val[k]
            const keyJson = JSON.stringify(k)

            const fullKey = parentPath ? `${parentPath}.${k}` : k
            const valueJson = render(v, level + 1, fullKey)

            const commentKey = usePath ? fullKey : k
            const comment = commentMap[commentKey] ? `  // ${commentMap[commentKey]}` : ''
            const comma = (idx === keys.length - 1) ? '' : ','

            if (valueJson.includes('\n')) {
              const valueLines = valueJson.split('\n')
              lines.push(`${indent}${indentUnit}${keyJson}: ${valueLines[0]}`)
              for (let i = 1; i < valueLines.length; i++) {
                lines.push(`${indent}${indentUnit}${valueLines[i]}`)
              }
              lines[lines.length - 1] = `${lines[lines.length - 1]}${comma}${comment}`
            } else {
              lines.push(`${indent}${indentUnit}${keyJson}: ${valueJson}${comma}${comment}`)
            }
          })

          lines.push(`${indent}}`)
          return lines.join('\n')
        }

        return JSON.stringify(val)
      }

      return render(exampleObj, 0, '')
    },
  },

  watch: {
    $route() {
      this.hydrateFromRoute()
    }
  },
  computed: {
    // 按照语言显示不同的按钮文本
    copyCodeBtnText() {
      return {
        '繁体中文': '複製代碼',
        'English': 'Copy Code',
      }[this.$store.state.lang || 'English']; // 默认英语
    },
    payloadRaw() { return this.payload },
    responseBodyRaw() { return this.responseBody },
    unsubPayloadRaw() { return this.unsub_payload },
    dataUpdateDemoRaw() { return this.dataUpdateDemo },

    payloadHtml() {
      const v = this.payloadRaw
      if (typeof v === 'string') return v
      try { return JSON.stringify(v, null, 2) } catch (e) { return String(v) }
    },
    responseBodyHtml() {
      const v = this.responseBodyRaw
      if (typeof v === 'string') return v
      try { return JSON.stringify(v, null, 2) } catch (e) { return String(v) }
    },
    unsubPayloadHtml() {
      const v = this.unsubPayloadRaw
      if (typeof v === 'string') return v
      try { return JSON.stringify(v, null, 2) } catch (e) { return String(v) }
    },
    dataUpdateDemoHtml() {
      const v = this.dataUpdateDemoRaw
      if (typeof v === 'string') return v
      try { return JSON.stringify(v, null, 2) } catch (e) { return String(v) }
    },

    prismLang() {
      const m = {
        python: 'python',
        nodejs: 'javascript',
        golang: 'go',
        java: 'java',
        php: 'php',
        csharp: 'csharp',
      }
      return m[this.activeLang] || 'javascript'
    },
    // 数据更新示例：繁中 jsonc（自动注释）
    dataUpdateDemoJsoncZh() {
      const api = (this.content && this.content.api) ? this.content.api : {}
      const demoObj = this.safeParseJson(api.dataUpdateDemo) || this.safeParseJson(this.dataUpdateDemoRaw)
      const fieldList = api.response && Array.isArray(api.response.list) ? api.response.list : []
      const usePath = api.jsoncMode === 'path' || api.jsoncHier === true
      return this.buildJsonc(demoObj, fieldList, 'zh', usePath)
    },

    // 数据更新示例：英文 jsonc（自动注释）
    dataUpdateDemoJsoncEn() {
      const api = (this.content && this.content.api) ? this.content.api : {}
      const demoObj = this.safeParseJson(api.dataUpdateDemo) || this.safeParseJson(this.dataUpdateDemoRaw)
      const fieldList = api.response && Array.isArray(api.response.list) ? api.response.list : []
      const usePath = api.jsoncMode === 'path' || api.jsoncHier === true
      return this.buildJsonc(demoObj, fieldList, 'en', usePath)
    },
  },

  mounted() {
    // 注入预处理后的文档映射
    this.enDoc = enDoc
    this.cnDoc = cnDoc
    this.hydrateFromRoute()
    // 页面加载时检查当前路由
    this.updateAddressBasedOnRoute(this.$route.path);
    // 页面加载时，默认生成代码
    this.generateCode();
    // 页面加载时调整高度
    this.$nextTick(() => this.resizeAndHighlight())
  }
}
</script>



