const java = `
import javax.crypto.Mac;
import javax.crypto.spec.SecretKeySpec;
import java.io.BufferedReader;
import java.io.InputStreamReader;
import java.io.OutputStream;
import java.net.HttpURLConnection;
import java.net.URL;
import java.util.Map;
import java.util.TreeMap;
import com.google.gson.Gson;

public class TradeDemo {

    private String url = "PPRROOTTOOCCOOLL://HHOOSSTT";
    private String apiKey = "";
    private String secretKey = "";

    private static final char[] HEX_ARRAY = "0123456789ABCDEF".toCharArray();

    public static void main(String[] args) {
        TradeDemo h = new TradeDemo();
        String method = "MMEETTHHOODD";
        String path = "AAPPII";
        TreeMap<String, Object> parameters = new TreeMap<String, Object>();
        PPAAYYLLOOAADD
        long timestamp = System.currentTimeMillis();
        parameters.put("timestamp", timestamp);
        String valueToDigest = h.getMessageToDigest(parameters);
        String messageDigest = h.generateHmac256(valueToDigest);
        parameters.put("signature", messageDigest);
        String requestUrl = h.getRequestUrl(path);
        h.execute(requestUrl, method, parameters);
    }
    public static String bytesToHex(byte[] bytes) {
        char[] hexChars = new char[bytes.length * 2];
        for (int j = 0; j < bytes.length; j++) {
            int v = bytes[j] & 0xFF;
            hexChars[j * 2] = HEX_ARRAY[v >>> 4];
            hexChars[j * 2 + 1] = HEX_ARRAY[v & 0x0F];
        }
        return new String(hexChars);
    }

    byte[] hmac(String algorithm, byte[] key, byte[] message) throws Exception {
        Mac mac = Mac.getInstance(algorithm);
        mac.init(new SecretKeySpec(key, algorithm));
        return mac.doFinal(message);
    }

    String generateHmac256(String message) {
        try {
            byte[] bytes = hmac("HmacSHA256", secretKey.getBytes(), message.getBytes());
            String signature = bytesToHex(bytes);
            System.out.println("sign=" + signature);
            return signature;
        } catch (Exception e) {
            System.out.println("generateHmac256 expection:" + e);
        }
        return "";
    }

    String getMessageToDigest(TreeMap<String, Object> parameters) {
        Boolean first = true;
        String valueToDigest = "";
        for (Map.Entry<String, Object> e : parameters.entrySet()) {
            if (!first) {
                valueToDigest += "&";
            }
            first = false;
            String key = e.getKey();
            Object value = e.getValue();
            valueToDigest += key + "=" + value;
        }
        return valueToDigest;
    }
    
    String getRequestUrl(String path) {
        String urlStr = url + path;
        System.out.println(urlStr);
        return urlStr;
    }

    void execute(String requestUrl, String method, TreeMap<String, Object> bodyParams) {
        try {
            URL urlObj = new URL(requestUrl);
            HttpURLConnection conn = (HttpURLConnection) urlObj.openConnection();
            conn.setRequestMethod(method);
            conn.setRequestProperty("X-BX-APIKEY", apiKey);
            conn.setRequestProperty("Content-Type", "application/json");
            conn.setDoOutput(true);
            conn.setDoInput(true);

            // Write request body
            Gson gson = new Gson();
            String jsonBody = gson.toJson(bodyParams);
            try (OutputStream os = conn.getOutputStream()) {
                byte[] input = jsonBody.getBytes("utf-8");
                os.write(input, 0, input.length);
            }

            // Read response
            String result = "";
            String line = "";
            BufferedReader in = new BufferedReader(
                    new InputStreamReader(conn.getInputStream()));
            while ((line = in.readLine()) != null) {
                result += line;
            }

            System.out.println("demo: " + result);

        } catch (Exception e) {
            System.out.println("expection:" + e);
        }
    } 
}
`
