import { codeLangConfig2, CODE_LANG_KEY } from '../lang'

function generateCodeWs(api, codeLang, host, defaultCode) {
  const code = codeLangConfig2.find(item => item.value === codeLang)
  if (!code) {
    return defaultCode || 'No Code'
  }

  const url = window.location.href.toLowerCase();
  // 判断是否是账户信息推送（不需要订阅channel）
  const isAccountPush = url.indexOf('websocket-账户') > -1 || url.indexOf('websocket-account') > -1 || url.indexOf('/account') > -1;

  let codeStr = require("../ws/usdt-m/" + codeLang + '.js').default
  if( api && api.uri)
    codeStr = codeStr.replace(/AAPPII/g, api.uri)

  if (url.indexOf('/spot/') > -1 || url.indexOf('/3-现货/') > -1 || (url.indexOf('/spot') > -1 && url.indexOf('/cswap') === -1)) {
    codeStr = require("../ws/spot/" + codeLang + '.js').default
    if( api && api.uri)
      codeStr = codeStr.replace(/AAPPII/g, api.uri)
    if (isAccountPush) {
      codeStr = codeStr.replace(/HHOOSSTT/g, "wss://open-api-ws.bingx.com/market?listenKey=a8ea75681542e66f1a50a1616dd06ed77dab61baa0c296bca03a9b13ee5f2dd7")
    } else {
     codeStr = codeStr.replace(/HHOOSSTT/g, "wss://open-api-ws.bingx.com/market")
    }
  } else if (url.indexOf('/cswap/') > -1 || url.indexOf('/4-币本位/') > -1 || url.indexOf('/coin-m') > -1) {
    codeStr = require("../ws/cswap/" + codeLang + '.js').default
    if( api && api.uri)
      codeStr = codeStr.replace(/AAPPII/g, api.uri)
    if (isAccountPush) {
      codeStr = codeStr.replace(/HHOOSSTT/g, "wss://open-api-cswap-ws.bingx.com/market?listenKey=a8ea75681542e66f1a50a1616dd06ed77dab61baa0c296bca03a9b13ee5f2dd7")
    } else {
      codeStr = codeStr.replace(/HHOOSSTT/g, "wss://open-api-cswap-ws.bingx.com/market")
    }
  }
  else {
    if (isAccountPush) {
      codeStr = codeStr.replace(/HHOOSSTT/g, "wss://open-api-swap.bingx.com/swap-market?listenKey=a8ea75681542e66f1a50a1616dd06ed77dab61baa0c296bca03a9b13ee5f2dd7")
    }else {
      codeStr = codeStr.replace(/HHOOSSTT/g, "wss://open-api-swap.bingx.com/swap-market")
    }
  }

  // 如果是账户信息推送，移除订阅channel的代码块
  if (isAccountPush) {
    // 移除标记为订阅的代码块（使用正则匹配多行）
    codeStr = codeStr.replace(/\/\/ SUBSCRIBE_START[\s\S]*?\/\/ SUBSCRIBE_END/g, '');
    codeStr = codeStr.replace(/# SUBSCRIBE_START[\s\S]*?# SUBSCRIBE_END/g, '');
    codeStr = codeStr.replace(/\/\* SUBSCRIBE_START \*\/[\s\S]*?\/\* SUBSCRIBE_END \*\//g, '');
  } else {
    // 如果是行情推送，移除占位符标记，保留代码
    codeStr = codeStr.replace(/\/\/ SUBSCRIBE_START\n?/g, '');
    codeStr = codeStr.replace(/\/\/ SUBSCRIBE_END\n?/g, '');
    codeStr = codeStr.replace(/# SUBSCRIBE_START\n?/g, '');
    codeStr = codeStr.replace(/# SUBSCRIBE_END\n?/g, '');
    codeStr = codeStr.replace(/\/\* SUBSCRIBE_START \*\/\n?/g, '');
    codeStr = codeStr.replace(/\/\* SUBSCRIBE_END \*\/\n?/g, '');
  }

  // 对于 Golang，需要将转义的反引号替换为真正的反引号
  if (codeLang === 'golang') {
    codeStr = codeStr.replace(/\\`/g, '`')
  }

  // PHP 需要先去掉开头的 "php" 文本
  if (codeLang === 'php') {
    codeStr = codeStr.replace(/^php\s*/, '')
  }



  return codeStr

}

export default generateCodeWs



