import Vue from 'vue'
import Router from 'vue-router'
import axios from 'axios'
import VueScrollTo from 'vue-scrollto'
import VueClipboard from 'vue-clipboard2'
import {docs as apiDocs} from './Docs/index'


import Element from 'element-ui'
import 'element-ui/lib/theme-chalk/index.css'

import store from './store'
import App from './App.vue'


Vue.use(VueScrollTo, {
    container: "#scroll-container",
    duration: 500,
    easing: "ease",
    offset: 0,
    force: true,
})
Vue.use(Element)
Vue.use(VueClipboard)
Vue.use(Router)
// console.log("apiDocs:", apiDocs)
Vue.prototype.$axios = axios
Vue.config.productionTip = false
import MainContent from './views/MainContent.vue';

// 预加载所有的 content 数据并存入 Vuex
apiDocs.forEach(menu => {
    menu.list.forEach(subMenub => {
        const isTwo = subMenub.twoLevel === true && Array.isArray(subMenub.docs) && subMenub.docs.length > 0;

        // 对 subMenub.en 进行 encodeURIComponent
        const encodedSubMenu = encodeURIComponent(subMenub.en);

        if (isTwo) {
            // 二级直达：使用 docs[0] 作为该二级的内容
            const docObj = subMenub.docs[0];
            const pathZH2 = `/zh-tw/${menu.en}/${encodedSubMenu}`;
            const pathEN2 = `/en/${menu.en}/${encodedSubMenu}`;
            store.dispatch('updateContent', { path: pathZH2, content: docObj });
            store.dispatch('updateContent', { path: pathEN2, content: docObj });
        } else {
            // 维持原有的三级：为每篇文档建立 3 级路径
            subMenub.docs.forEach(docObj => {
                const pathZH = `/zh-tw/${menu.en}/${encodedSubMenu}/${encodeURIComponent(docObj.doc.title)}`;
                const pathEN = `/en/${menu.en}/${encodedSubMenu}/${encodeURIComponent(docObj.doc.en)}`;
                store.dispatch('updateContent', { path: pathZH, content: docObj });
                store.dispatch('updateContent', { path: pathEN, content: docObj });
            });
        }
    });
});



const routes = [];

apiDocs.forEach(menu => {
    menu.list.forEach(subMenub => {
        const isTwo = subMenub.twoLevel === true && Array.isArray(subMenub.docs) && subMenub.docs.length > 0;

        // 对 menu.en 和 subMenub.en 都进行 encodeURIComponent
        const encodedMenuEn = encodeURIComponent(menu.en);
        const encodedSubMenu = encodeURIComponent(subMenub.en);

        if (isTwo) {
            // 二级直达路由（点二级菜单就到 MainContent）
            // 同时添加编码和未编码的版本，以支持不同的访问方式
            const pathZH2_1 = `/zh-tw/${menu.en}/${encodedSubMenu}`;
            const pathZH2_2 = `/zh-tw/${encodedMenuEn}/${encodedSubMenu}`;
            const pathEN2_1 = `/en/${menu.en}/${encodedSubMenu}`;
            const pathEN2_2 = `/en/${encodedMenuEn}/${encodedSubMenu}`;

            routes.push({ path: pathZH2_1, component: MainContent, props: true });
            routes.push({ path: pathZH2_2, component: MainContent, props: true });
            routes.push({ path: pathEN2_1, component: MainContent, props: true });
            routes.push({ path: pathEN2_2, component: MainContent, props: true });

            // （可选）把历史的三级链接重定向回二级，避免 404
            routes.push({ path: `/zh-tw/${menu.en}/${encodedSubMenu}/*`, redirect: pathZH2_1 });
            routes.push({ path: `/en/${menu.en}/${encodedSubMenu}/*`, redirect: pathEN2_1 });

        } else {
            // 非 twoLevel：按原来的三级生成
            subMenub.docs.forEach(docObj => {
                // 同时添加编码和未编码的版本
                const pathZH1 = `/zh-tw/${menu.en}/${encodedSubMenu}/${encodeURIComponent(docObj.doc.title)}`;
                const pathZH2 = `/zh-tw/${encodedMenuEn}/${encodedSubMenu}/${encodeURIComponent(docObj.doc.title)}`;
                const pathEN1 = `/en/${menu.en}/${encodedSubMenu}/${encodeURIComponent(docObj.doc.en)}`;
                const pathEN2 = `/en/${encodedMenuEn}/${encodedSubMenu}/${encodeURIComponent(docObj.doc.en)}`;
                routes.push({
                    path: pathZH1,
                    component: MainContent,
                    props: true
                });
                routes.push({
                    path: pathZH2,
                    component: MainContent,
                    props: true
                });
                routes.push({
                    path: pathEN1,
                    component: MainContent,
                    props: true
                });
                routes.push({
                    path: pathEN2,
                    component: MainContent,
                    props: true
                });
            });
        }
    });
});


// 固定页
routes.push({ path: "/zh-tw/info", component: MainContent });
routes.push({ path: "/en/info", component: MainContent });
routes.push({ path: "/zh-tw/changes/logs", component: MainContent });
routes.push({ path: "/en/changes/logs", component: MainContent });

// 默认重定向
routes.unshift({ path: '/', redirect: '/en/info' });
const router = new Router({
    routes // 简写，等同于 `routes: routes`
});

new Vue({
    el: '#app',
    router,
    store, //VUEX
    render: h => h(App),
})



