
const  csharp = `
using System;
using System.Collections.Generic;
using System.Linq;
using System.Net.Http;
using System.Security.Cryptography.X509Certificates;
using System.Threading.Tasks;
using System.Security.Cryptography;
using System.Text;
using Newtonsoft.Json;

namespace BingXApi
{
    class Program
    {
    static void Main(string[] args)
    {
        string API_KEY = "";
        string API_SECRET = "";
        string HOST = "HHOOSSTT";
        var api = new
        {
            uri = "AAPPII",
            method = "MMEETTHHOODD",
            payload = new
            PPAAYYLLOOAADD,
            protocol = "https"
        };

        DoRequest(api.protocol, HOST, api.uri, api.method, API_KEY, API_SECRET, api.payload).Wait();
    }

    static async Task DoRequest(string protocol, string host, string api, string method, string API_KEY, string API_SECRET, object payload)
    {
        long timestamp = DateTimeOffset.Now.ToUnixTimeMilliseconds();
        
        var paramsDict = new Dictionary<string, string>();
        if (payload != null)
        {
            foreach (var property in payload.GetType().GetProperties())
            {
                string key = property.Name;
                string value = property.GetValue(payload)?.ToString() ?? "";
                paramsDict[key] = value;
            }
        }
        paramsDict["timestamp"] = timestamp.ToString();
        
        var sortedParams = paramsDict.OrderBy(p => p.Key).ToList();
        
        string parameters = "";
        bool first = true;
        foreach (var param in sortedParams)
        {
            if (!first)
            {
                parameters += "&";
            }
            first = false;
            parameters += $"{param.Key}={param.Value}";
        }

        string sign = CalculateHmacSha256(parameters, API_SECRET);
        
        // Build request body with all parameters including timestamp and signature
        var bodyDict = new Dictionary<string, object>();
        if (payload != null)
        {
            foreach (var property in payload.GetType().GetProperties())
            {
                string key = property.Name;
                object value = property.GetValue(payload);
                bodyDict[key] = value;
            }
        }
        bodyDict["timestamp"] = timestamp;
        bodyDict["signature"] = sign;
        
        string url = $"{protocol}://{host}{api}";

        Console.WriteLine("protocol: " + protocol);
        Console.WriteLine("method: " + method);
        Console.WriteLine("host: " + host);
        Console.WriteLine("api: " + api);
        Console.WriteLine("parameters: " + parameters);
        Console.WriteLine("sign: " + sign);
        Console.WriteLine(method + " " + url);

        using (HttpClientHandler handler = new HttpClientHandler())
        {
            handler.ServerCertificateCustomValidationCallback = (sender, cert, chain, sslPolicyErrors) => true;

            using (HttpClient client = new HttpClient(handler))
            {
                client.DefaultRequestHeaders.Add("X-BX-APIKEY", API_KEY);
                string jsonBody = JsonConvert.SerializeObject(bodyDict);
                var content = new StringContent(jsonBody, Encoding.UTF8, "application/json");
                
                HttpResponseMessage response;
                if (method.ToUpper() == "GET")
                {
                    response = await client.GetAsync(url);
                }
                else if (method.ToUpper() == "POST")
                {
                    response = await client.PostAsync(url, content);
                }
                else if (method.ToUpper() == "DELETE")
                {
                    response = await client.DeleteAsync(url);
                }
                else if (method.ToUpper() == "PUT")
                {
                    response = await client.PutAsync(url, content);
                }
                else
                {
                    throw new NotSupportedException("Unsupported HTTP method: " + method);
                }
                response.EnsureSuccessStatusCode();
                string responseBody = await response.Content.ReadAsStringAsync();
                Console.WriteLine("Response status code: " + response.StatusCode);
                Console.WriteLine("Response body: " + responseBody);
            }
        }
    }

    static string CalculateHmacSha256(string input, string key)
    {
        byte[] keyBytes = System.Text.Encoding.UTF8.GetBytes(key);
        byte[] inputBytes = System.Text.Encoding.UTF8.GetBytes(input);
        using (HMACSHA256 hmac = new HMACSHA256(keyBytes))
        {
            byte[] hashBytes = hmac.ComputeHash(inputBytes);
            return BitConverter.ToString(hashBytes).Replace("-", "").ToLower();
        }
    }
}
}`
export default  csharp




