
const golang = `
package main

import (
	"encoding/json"
	"crypto/hmac"
	"fmt"
	"time"
	"net/http"
	"io/ioutil"
	"bytes"
	"crypto/sha256"
	"encoding/hex"
  "strings"
  "sort"
)
const HOST = "HHOOSSTT"
const API_KEY = ""
const API_SECRET = ""
func main() {

  dataStr := ^AAPPII^
  payload := ^PPAAYYLLOOAADD^
  TIMESTAMP := time.Now().UnixNano()/1e6
  apiMap := getParameters(dataStr, payload, TIMESTAMP)
  sign := computeHmac256(fmt.Sprintf("%v",apiMap["parameters"]), API_SECRET)
  fmt.Println("parameters:",fmt.Sprintf("%v",apiMap["parameters"]))
  fmt.Println("sign:",sign)
  
  // Build request body
  bodyMap := make(map[string]interface{})
  payloadMap := make(map[string]interface{})
  json.Unmarshal([]byte(payload), &payloadMap)
  for k, v := range payloadMap {
    bodyMap[k] = v
  }
  bodyMap["timestamp"] = TIMESTAMP
  bodyMap["signature"] = sign
  bodyBytes, _ := json.Marshal(bodyMap)
  
  url := fmt.Sprintf("%v://%s%v",apiMap["protocol"],HOST,apiMap["uri"])
  method := fmt.Sprintf("%v",apiMap["method"])
  client := &http.Client {}
  fmt.Println("url:",url)
  fmt.Println("method:",method)
  req, err := http.NewRequest(method, url, bytes.NewBuffer(bodyBytes))

  if err != nil {
    fmt.Println(err)
    return
  }
  req.Header.Add("X-BX-APIKEY", API_KEY)
  req.Header.Add("Content-Type", "application/json")
  res, err := client.Do(req)
  if err != nil {
    fmt.Println(err)
    return
  }
  defer res.Body.Close()

  body, err := ioutil.ReadAll(res.Body)
  if err != nil {
    fmt.Println(err)
    return
  }
  fmt.Println(string(body))
}

func computeHmac256(strMessage string, strSecret string) string {
	key := []byte(strSecret)
	h := hmac.New(sha256.New, key)
	h.Write([]byte(strMessage))
	return hex.EncodeToString(h.Sum(nil))
}
func getParameters(dataStr string, payload string, timestemp int64) map[string]interface{} {
	var apiMap map[string]interface{}
	var payloadMap map[string]interface{}
	err := json.Unmarshal([]byte(dataStr), &apiMap)
	if err != nil {
		fmt.Printf("json to map error,err:%s", err)
		return apiMap
	}
	err = json.Unmarshal([]byte(payload), &payloadMap)
	if err != nil {
		fmt.Printf("json to map error,err:%s", err)
		return apiMap
	}

	keys := make([]string, 0, len(payloadMap))
	for k := range payloadMap {
		keys = append(keys, k)
	}
	sort.Strings(keys)

	parameters := ""
	for _, key := range keys {
		value := payloadMap[key]
		parameters += key + "=" + fmt.Sprintf("%v", value) + "&"
	}

	parameters += "timestamp=" + fmt.Sprintf("%d", timestemp)
	apiMap["parameters"] = parameters
	return apiMap
}`
export default golang




