import 'prismjs/components/prism-go'
import 'prismjs/components/prism-java'
import 'prismjs/components/prism-bash'

// 如果你要 php，再加这两行（顺序别反）
import 'prismjs/components/prism-markup-templating'
import 'prismjs/components/prism-php'


export default {
  name: 'RestfulApi',
  components: {CopyPath},
  props: {
    content: {type: Object, default: () => ({})},
    codeLang: {type: String, default: 'json'},
    stringify: {type: Boolean, default: true}
  },
  data() {
    return {
      activeLang: 'python',
      activeCodeTab: this.codeLang,
      tableData: [
        {env: 'PROD', address: 'https://open-api.bingx.com'},
        {env: 'VST', address: 'https://open-api-vst.bingx.com'}
      ],
      msgMap: {
        success: {
          '繁体中文': '已複製到剪貼簿',
          English: 'Copied to clipboard'
        },
        error: {
          '繁体中文': '複製失敗',
          English: 'Copy Failed'
        }
      },
      demoHtml: ''
    }
  },
  computed: {
    restApiRequest() {
      var api = (this.content && this.content.api) ? this.content.api : null
      var list = api && api.request && Array.isArray(api.request.list) ? api.request.list : []
      return list
    },
    restApiResponse() {
      var api = (this.content && this.content.api) ? this.content.api : null
      var list = api && api.response && Array.isArray(api.response.list) ? api.response.list : []
      return list
    },
    errorList() {
      var api = (this.content && this.content.api) ? this.content.api : null
      var list = api && api.error && Array.isArray(api.error.list) ? api.error.list : []
      return list
    },
    payloadRaw() {
      var api = (this.content && this.content.api) ? this.content.api : null
      return api && api.payload ? api.payload : ''
    },
    responseBodyRaw() {
      var api = (this.content && this.content.api) ? this.content.api : null
      return api && api.responseBody ? api.responseBody : ''
    },
    payloadHtml() {
      var v = this.payloadRaw
      if (typeof v === 'string') return v
      if (this.stringify) {
        try {
          return JSON.stringify(v, null, 2)
        } catch (e) {
          return String(v)
        }
      }
      return String(v)
    },
    responseBodyHtml() {
      var v = this.responseBodyRaw
      if (typeof v === 'string') return v
      if (this.stringify) {
        try {
          return JSON.stringify(v, null, 2)
        } catch (e) {
          return String(v)
        }
      }
      return String(v)
    },
    copyCodeBtnText() {
      return {
        '繁体中文': '複製代碼',
        English: 'Copy Code'
      }[this.$store.state.lang || 'English']
    },
    prismLang() {
      const m = {
        python: 'python',
        javascript: 'javascript',
        golang: 'go',
        java: 'java',
        php: 'php',
        shell: 'bash'
      }
      return m[this.activeLang] || 'javascript'
    }
  },
  methods: {
    scrollToElement(tab) {
      var label = tab && tab.label ? tab.label : ''
      var el = this.$refs[label]
      if (el && el.scrollIntoView) {
        el.scrollIntoView({behavior: 'smooth'})
      }
    },
    tableRowClassName(args) {
      var row = args && args.row ? args.row : null
      if (!row) return ''
      if (row.type === 'breaking' || row.level === 'breaking') return 'warning-row'
      if (row.type === 'fix' || row.level === 'success') return 'success-row'
      return ''
    },
    generateCode() {
      const api = {
        uri: (this.content && this.content.api && this.content.api.uri) || '',
        method: (this.content && this.content.api && this.content.api.method) || 'GET',
        payload: (this.content && this.content.api && this.content.api.payload) || {},
        useBodyParams: (this.content && this.content.api && this.content.api.useBodyParams) || false,
        protocol: 'https'
      }
      const prod = this.tableData.find(item => item.env === 'PROD')
      const addr = prod && prod.address ? prod.address : ''
      const u = new URL(addr);
      const protocol = u.protocol.replace(":", ""); // https
      const host = u.host;
      this.demoHtml = generateCodeJson(api, this.activeLang, protocol, host, 'No code available')
      this.$nextTick(() => {
        this.resizeAndHighlight()
      })
    },
    onCopy() {
      this.$message.success(this.msgMap.success[this.$store.state.lang])
    },
    onError() {
      this.$message.error(this.msgMap.error[this.$store.state.lang])
    },
    resizeAndHighlight() {
      this.$nextTick(() => {
        const targets = [
          {block: this.$refs.payloadBlock, code: this.$refs.payloadCode, lang: 'json', raw: this.payloadHtml},
          {block: this.$refs.responseBlock, code: this.$refs.responseCode, lang: 'json', raw: this.responseBodyHtml},
          {block: this.$refs.demoBlock, code: this.$refs.demoCode, lang: this.prismLang, raw: this.demoHtml},

          {block: this.$refs.payloadBlockEn, code: this.$refs.payloadCodeEn, lang: 'json', raw: this.payloadHtml},
          {
            block: this.$refs.responseBlockEn,
            code: this.$refs.responseCodeEn,
            lang: 'json',
            raw: this.responseBodyHtml
          },
          {block: this.$refs.demoBlockEn, code: this.$refs.demoCodeEn, lang: this.prismLang, raw: this.demoHtml}
        ].filter(t => t.block && t.code)

        targets.forEach(t => {
          // 切语言 class（Prism 依赖这个）
          t.code.className = `language-${t.lang}`

          // 永远用“数据源”回填，不要读 textContent
          t.code.textContent = (t.raw == null ? '' : String(t.raw))

          Prism.highlightElement(t.code)
        })

        requestAnimationFrame(() => {
          targets.forEach(t => {
            t.block.style.height = 'auto'
            t.block.style.height = t.block.scrollHeight + 'px'
          })
        })
      })
    },
    onLangTabClick(tab) {
      // Element UI 的 tab 会带 name；强制同步，避免 activeLang 没更新
      if (tab && tab.name) this.activeLang = tab.name
      this.generateCode()
      this.$nextTick(() => this.resizeAndHighlight())
    },
  },
  mounted() {
    this.generateCode()
    this.$nextTick(() => this.resizeAndHighlight())
  },
  watch: {
    content: {
      deep: true,
      handler() {
        this.generateCode()
        this.$nextTick(() => this.resizeAndHighlight())
      }
    },
    activeLang() {
      this.generateCode()
      this.$nextTick(() => this.resizeAndHighlight())
    },
    codeLang(newVal) {
      this.activeCodeTab = newVal || 'json'
      this.$nextTick(() => this.resizeAndHighlight())
    }
  }

}
</script>



