import { codeLangConfig, CODE_LANG_KEY } from '../lang'

function generateCode(api, codeLang, protocol,host, defaultCode) {
  const code = codeLangConfig.find(item => item.value === codeLang)

  if (!code) {
    return defaultCode || 'No Code'
  }
  const api2 = {}
  
  // Check if useBodyParams is true, then use body template
  const useBodyParams = api.useBodyParams === true
  const templateSuffix = useBodyParams ? '-body' : ''
  let codeStr = require("../rest/" + codeLang + templateSuffix + '.js').default

  let payload = api.payload
  if (Array.isArray(api.payload)) {
    payload = api.payload[0].payload
  }

  if (code.value === CODE_LANG_KEY.js) {
    api2.uri = api.uri
    api2.method = api.method
    api2.payload = payload
    api2.protocol = protocol
    codeStr = codeStr.replace(/AAPPII/g, JSON.stringify(api2, null, 4))
    codeStr = codeStr.replace(/HHOOSSTT/g, host)
    // 去掉开头的换行符，确保代码顶格显示
    codeStr = codeStr.replace(/^\n/, '')
    return codeStr
  } else if (codeLang === CODE_LANG_KEY.shell) {
    const parts = []
    for (const key in payload) {
      if (key === "timestamp") continue

      const value = payload[key]
      let valueStr = String(value)

      // PARAMETERS='...' 只需要转义单引号，不要动双引号，不要额外加反斜杠
      valueStr = valueStr.replace(/'/g, `'\\''`)

      parts.push(`${key}=${valueStr}`)
    }

    const parameters = parts.join("&")

    codeStr = codeStr.replace(/AAPPII/g, api.uri)
    codeStr = codeStr.replace(/HHOOSSTT/g, host)
    codeStr = codeStr.replace(/PPRROOTTOOCCOOLL/g, protocol)
    codeStr = codeStr.replace(/MMEETTHHOODD/g, api.method)
    codeStr = codeStr.replace(/PPAARRAAMMEETTEERRSS/g, parameters)
    codeStr = codeStr.replace(/\^/g, '`')
    return codeStr
  } else if (codeLang === CODE_LANG_KEY.go) {
    api2.uri = api.uri
    api2.method = api.method
    // api2.payload = payload
    api2.protocol = protocol
    codeStr = codeStr.replace(/\^/g, '`')
    codeStr = codeStr.replace(/AAPPII/g, JSON.stringify(api2, null, 4))
    codeStr = codeStr.replace(/PPAAYYLLOOAADD/g, JSON.stringify(payload, null, 4))
    codeStr = codeStr.replace(/HHOOSSTT/g, host)
    // 去掉开头的换行符，确保代码顶格显示
    codeStr = codeStr.replace(/^\n/, '')
    return codeStr
  } else if (codeLang === CODE_LANG_KEY.java) {
    api2.uri = api.uri
    api2.method = api.method
    api2.protocol = protocol
    codeStr = codeStr.replace(/\^/g, '`')
    codeStr = codeStr.replace(/AAPPII/g, api2.uri)
    let str = ``
    for (const prop in payload) {
      const value = payload[prop]
      let valueStr
      if (typeof value === 'string') {
        // 转义 Java 字符串中的特殊字符：双引号、反斜杠等
        valueStr = JSON.stringify(value)
      } else {
        // 对于数字、布尔值等，也需要转换为字符串字面量
        valueStr = JSON.stringify(String(value))
      }
      str += `
        parameters.put("${prop}", ${valueStr});`
    }
    codeStr = codeStr.replace(/PPAAYYLLOOAADD/g, str)
    codeStr = codeStr.replace(/HHOOSSTT/g, host)
    codeStr = codeStr.replace(/MMEETTHHOODD/g, api2.method)
    codeStr = codeStr.replace(/PPRROOTTOOCCOOLL/g, api2.protocol)
    return codeStr
  } else if (codeLang === CODE_LANG_KEY.python) {
    api2.uri = api.uri
    api2.method = api.method
    // api2.payload = payload
    api2.protocol = protocol
    codeStr = codeStr.replace(/\^/g, '`')
    codeStr = codeStr.replace(/AAPPII/g, api2.uri)
    codeStr = codeStr.replace(/PPAAYYLLOOAADD/g, JSON.stringify(payload, null, 4))
    codeStr = codeStr.replace(/HHOOSSTT/g, host)
    codeStr = codeStr.replace(/PPRROOTTOOCCOOLL/g, api2.protocol)
    codeStr = codeStr.replace(/MMEETTHHOODD/g, api2.method)
    let parseParamFunction = `def parseParam(paramsMap):
    sortedKeys = sorted(paramsMap)
    paramsList = []
    urlParamsList = []
    for x in sortedKeys:
        value = paramsMap[x]
        paramsList.append("%s=%s" % (x, value))
    timestamp = str(int(time.time() * 1000))
    paramsStr = "&".join(paramsList)
    if paramsStr != "": 
        paramsStr = paramsStr + "&timestamp=" + timestamp
    else:
        paramsStr = "timestamp=" + timestamp
    contains = '[' in paramsStr or '{' in paramsStr
    for x in sortedKeys:
        value = paramsMap[x]
        if contains:
            encodedValue = urllib.parse.quote(str(value), safe='')
            urlParamsList.append("%s=%s" % (x, encodedValue))
        else:
            urlParamsList.append("%s=%s" % (x, value))
    urlParamsStr = "&".join(urlParamsList)
    if urlParamsStr != "": 
        urlParamsStr = urlParamsStr + "&timestamp=" + timestamp
    else:
        urlParamsStr = "timestamp=" + timestamp
    return paramsStr, urlParamsStr`
    codeStr = codeStr.replace(/PPAARRSSTTFFUUNNCCTTIIOONN/g, parseParamFunction)
    return codeStr
  } else if (codeLang === CODE_LANG_KEY.csharp) {
    api2.uri = api.uri
    api2.method = api.method
    // api2.payload = payload
    api2.protocol = protocol
    let payloadStr = ""
    let first = true
    for (const prop in payload) {
      if (!first) {
        payloadStr += ",\n            "
      }
      first = false
      const value = payload[prop]
      let valueStr
      if (typeof value === 'string') {
        valueStr = JSON.stringify(value)
      } else {
        valueStr = String(value)
      }
      payloadStr += `            ${prop} = ${valueStr}`
    }

    codeStr = codeStr.replace(/\^/g, '`')
    codeStr = codeStr.replace(/AAPPII/g, api2.uri)
    codeStr = codeStr.replace(/PPAAYYLLOOAADD/g, payloadStr)
    codeStr = codeStr.replace(/HHOOSSTT/g, host)
    codeStr = codeStr.replace(/PPRROOTTOOCCOOLL/g, api2.protocol)
    codeStr = codeStr.replace(/MMEETTHHOODD/g, api2.method)
    return codeStr
  } else if (codeLang === CODE_LANG_KEY.php) {
    api2.uri = api.uri
    api2.method = api.method
    // api2.payload = payload
    api2.protocol = protocol
    let payloadStr = ""
    if (payload && typeof payload === 'object') {
      let first = true
      for (const prop in payload) {
        if (!first) {
          payloadStr += ",\n            "
        }
        first = false
        const value = payload[prop]
        let valueStr
        if (typeof value === 'string') {
          valueStr = JSON.stringify(value)
        } else {
          valueStr = JSON.stringify(String(value))
        }
        payloadStr += `"${prop}" => ${valueStr}`
      }
    }

    codeStr = codeStr.replace(/\^/g, '`')
    codeStr = codeStr.replace(/AAPPII/g, api2.uri)
    codeStr = codeStr.replace(/PPAAYYLLOOAADD/g, payloadStr)
    codeStr = codeStr.replace(/HHOOSSTT/g, host)
    codeStr = codeStr.replace(/PPRROOTTOOCCOOLL/g, api2.protocol)
    codeStr = codeStr.replace(/MMEETTHHOODD/g, api2.method)
    // 去掉开头的换行符和 "php" 文本，确保代码顶格显示
    codeStr = codeStr.replace(/^php\n/, '')
    codeStr = codeStr.replace(/^\n/, '')
    return codeStr
  } else {
    return defaultCode || 'No Code'
  }
}

export default generateCode



