  line-height: 1.5;
  overflow-wrap: break-word;
  word-wrap: break-word;
}
</style>
<script>
import { docs as apiDocs } from "./Docs/index";
import elementLocale from "element-ui/lib/locale";
import enLocale from "element-ui/lib/locale/lang/en";
import zhTWLocale from "element-ui/lib/locale/lang/zh-TW";
export default {
  components: {},

  data() {
    return {
      apiDocs: [],
      allContent: {}, // 本地：路径 -> { doc }（doc 内含 api 等）
      lang: "English", // 仅用于本组件内部逻辑；模板仍用 $store.state.lang
      activeIndexAside: this.$route.path,
      activeIndex: "99",
      restaurants: [], // 搜索源：[{ path, value(uri) }]
      searchData: "",
      state: "",
      timeout: null
    };
  },

  watch: {
    $route(to) {
      const arr = to.path.split("/");
      this.lang = arr[1] && arr[1] === "zh-tw" ? "繁体中文" : "English";
      // 同步到全局 store，仅用于你模板里的 v-if 判断
      this.$store.commit("changeLang", this.lang);

      // 更新 activeIndex
      this.activeIndex = "99";
      // 更新 activeIndexAside，确保路径格式与菜单项的 index 一致
      // 需要对路径进行编码处理，以匹配菜单项的 index 格式
      this.updateActiveIndexAside(to.path);

      // 路由变更后，重建搜索源（按语言过滤）
      this.restaurants = this.loadAll();
      // 确保目标菜单项滚动到最上面
      window.scrollTo(0, 0);
      
      // 使用 $nextTick 确保 DOM 更新后手动设置菜单激活状态
      this.$nextTick(() => {
        if (this.$refs.menu) {
          this.$refs.menu.activeIndex = this.activeIndexAside;
        }
      });
    },
    "$store.state.lang"(val) {
      if (val === "繁体中文") {
        elementLocale.use(zhTWLocale);
      } else {
        elementLocale.use(enLocale);
      }
    }
  },

  mounted() {
    // 打印当前路由路径
    console.log("Current route path:", this.$route.path);

    // 打印当前语言状态
    // console.log('Current language in store:', this.$store.state.lang);

    const arr = this.$route.path.split("/");
    this.lang = arr[1] && arr[1] === "zh-tw" ? "繁体中文" : "English";
    this.$store.commit("changeLang", this.lang);

    if (this.$store.state.lang === "繁体中文") {
      elementLocale.use(zhTWLocale);
    } else {
      elementLocale.use(enLocale);
    }

    // 打印语言状态变化后的值
    // console.log('Language after update:', this.lang);

    // 打印 apiDocs 数据

    this.apiDocs = apiDocs;
    // console.log('API Docs data:', this.apiDocs);

    this.allContent = this.buildAllContentIndex();
    // console.log('allContent:', this.allContent);

    // 初始化菜单与搜索
    this.activeIndex = "99";
    // 初始化 activeIndexAside，确保格式正确
    this.updateActiveIndexAside(this.$route.path);
    this.restaurants = this.loadAll();

    // console.log('Restaurants (search source):', this.restaurants);
    // console.log('activeIndex:', this.activeIndex);
    console.log("activeIndexAside:", this.activeIndexAside);
  },

  methods: {
    /** 更新 activeIndexAside，确保路径格式与菜单项的 index 一致 */
    updateActiveIndexAside(path) {
      // 菜单项的 index 格式：menu.en 不编码，subMenu.en 和后续段编码
      // 例如：/en/Quick Start/Signature%20Authentication
      const pathParts = path.split('/')
      if (pathParts.length >= 3) {
        const encodedPathParts = [pathParts[0]] // 空字符串
        encodedPathParts.push(pathParts[1]) // 语言段（en 或 zh-tw），不编码
        
        // 先解码所有段，然后重新构建
        const decodedParts = []
        for (let i = 2; i < pathParts.length; i++) {
          const segment = pathParts[i]
          if (segment) {
            try {
              decodedParts.push(decodeURIComponent(segment))
            } catch (e) {
              decodedParts.push(segment)
            }
          } else {
            decodedParts.push(segment)
          }
        }
        
        // menu.en 段（索引 0 在 decodedParts 中），保持不编码
        if (decodedParts.length > 0) {
          encodedPathParts.push(decodedParts[0])
        }
        
        // 从索引 1 开始，这些是 subMenu.en 和后续段，需要编码
        for (let i = 1; i < decodedParts.length; i++) {
          encodedPathParts.push(encodeURIComponent(decodedParts[i]))
        }
        
        this.activeIndexAside = encodedPathParts.join('/')
      } else {
        // 对于简单路径（如 /en/info），直接使用
        this.activeIndexAside = path
      }
    },

    /** 将 Docs 构造成本地 allContent 索引：{ [path]: { doc } } */
    buildAllContentIndex() {
      const enMap = {};
      const zhMap = {};

      apiDocs.forEach(menu => {
        menu.list.forEach(subMenu => {
          const isTwo =
            subMenu.twoLevel === true &&
            Array.isArray(subMenu.docs) &&
            subMenu.docs.length > 0;
          const entryIndex = Number.isInteger(subMenu.entryIndex)
            ? subMenu.entryIndex
            : 0;

          // 对 subMenu.en 进行 encodeURIComponent
          const encodedSubMenuEn = encodeURIComponent(subMenu.en);

          if (isTwo) {
            // 二级直达：docs[entryIndex] 作为该二级的内容
            const docObj = subMenu.docs[entryIndex];
            const keyZH2 = `/zh-tw/${menu.en}/${encodedSubMenuEn}`;
            const keyEN2 = `/en/${menu.en}/${encodedSubMenuEn}`;
            zhMap[keyZH2] = docObj.doc;
            enMap[keyEN2] = docObj.doc;
          } else {
            // 原三极路径
            subMenu.docs.forEach(docObj => {
              if (docObj.pathOri === "./概述.json") {
                zhMap["/zh-tw/info"] = docObj.doc;
                enMap["/en/info"] = docObj.doc;
              } else if (docObj.pathOri === "./更新記錄.json") {
                zhMap["/zh-tw/changes/logs"] = docObj.doc;
                enMap["/en/changes/logs"] = docObj.doc;
              } else {
                const keyZH = `/zh-tw/${
                  menu.en
                }/${encodedSubMenuEn}/${encodeURIComponent(docObj.doc.title)}`;
                const keyEN = `/en/${
                  menu.en
                }/${encodedSubMenuEn}/${encodeURIComponent(docObj.doc.en)}`;
                zhMap[keyZH] = docObj.doc;
                enMap[keyEN] = docObj.doc;
              }
            });
          }
        });
      });

      const all = {};
      Object.keys(enMap).forEach(p => {
        all[p] = { doc: enMap[p] };
      });
      Object.keys(zhMap).forEach(p => {
        all[p] = { doc: zhMap[p] };
      });
      return all;
    },

    handleSearch() {
      console.log("Searching for:", this.input2);
    },
    handleOpen() {
      console.log("Menu opened");
    },
    handleClose() {
      console.log("Menu closed");
    },

    /** 语言下拉切换：只改 URL，不直接写 $store.state.lang */
    onChange(value) {
      const currentPath = this.$route.path;
      const newLangSeg = value === "繁体中文" ? "zh-tw" : "en";
      
      // 首先尝试从 allContent 中查找当前路径对应的文档
      let currentNode = null;
      let currentPathKey = null;
      
      // 尝试多种路径格式查找当前文档
      const pathVariants = this.generatePathVariants(currentPath);
      for (const variant of pathVariants) {
        if (this.allContent[variant]) {
          currentNode = this.allContent[variant];
          currentPathKey = variant;
          break;
        }
      }
      
      let newPath = '';
      
      // info 与 changes/logs 特例
      if (currentPath.includes('/info') || currentPath.includes('/changes/logs')) {
        newPath = currentPath.replace(/\/zh-tw|\/en/, `/${newLangSeg}`);
      } else if (currentNode && currentNode.doc) {
        // 找到了文档，从 allContent 中找到新语言对应的路径
        const doc = currentNode.doc;
        
        // 遍历 allContent，找到新语言下包含相同文档的路径
        // 通过比较 doc.title 和 doc.en 来匹配
        let foundPath = null;
        for (const [path, content] of Object.entries(this.allContent)) {
          if (path.startsWith(`/${newLangSeg}/`) && content.doc) {
            // 对于三级路径，通过比较标题来匹配
            if (currentPathKey && currentPathKey.split('/').length >= 4) {
              // 三级路径：比较标题
              const currentTitle = currentNode.doc.title;
              const currentEn = currentNode.doc.en;
              const targetTitle = content.doc.title;
              const targetEn = content.doc.en;
              
              if ((newLangSeg === 'zh-tw' && currentTitle === targetTitle) ||
                  (newLangSeg === 'en' && currentEn === targetEn)) {
                foundPath = path;
                break;
              }
            } else {
              // 二级路径或其他：直接比较文档对象
              if (content.doc === doc) {
                foundPath = path;
                break;
              }
            }
          }
        }
        
        if (foundPath) {
          newPath = foundPath;
        } else {
          // 如果找不到，尝试根据当前路径结构构建
          const parts = currentPathKey ? currentPathKey.split('/') : currentPath.split('/');
          if (parts.length >= 4) {
            // 三级路径：替换语言段和标题
            const title = value === "繁体中文" ? doc.title : doc.en;
            newPath = `/${newLangSeg}/${parts[2]}/${parts[3]}/${encodeURIComponent(title)}`;
          } else if (parts.length === 4) {
            // 二级路径
            newPath = `/${newLangSeg}/${parts[2]}/${parts[3]}`;
          } else {
            newPath = currentPath.replace(/\/zh-tw|\/en/, `/${newLangSeg}`);
          }
        }
      } else {
        // 如果找不到文档，尝试直接替换语言段并标准化
        const parts = currentPath.split('/');
        parts[1] = newLangSeg;
        newPath = this.normalizePath(parts.join('/'));
      }
      
      // 如果新路径不存在，尝试多种格式
      if (!this.allContent[newPath]) {
        const alternatives = this.generatePathAlternatives(newPath);
        for (const alt of alternatives) {
          if (this.allContent[alt]) {
            newPath = alt;
            break;
          }
        }
      }

      this.$router.push(newPath).then(() => {
        // 路由切换后，更新搜索源
        this.restaurants = this.loadAll();
        this.$forceUpdate();
      }).catch(err => {
        console.error('Route navigation error:', err);
        console.error('Failed path:', newPath);
        console.error('Current path:', currentPath);
        // 如果导航失败，尝试跳转到默认页面
        const defaultPath = value === "繁体中文" ? "/zh-tw/info" : "/en/info";
        this.$router.push(defaultPath).then(() => {
          this.restaurants = this.loadAll();
        });
      });
    },
    
    /** 生成路径的多种变体用于查找 */
    generatePathVariants(path) {
      const variants = [path];
      const parts = path.split('/');
      
      if (parts.length >= 3) {
        // 标准化版本：menu.en 不编码，后续段编码
        const normalized = [parts[0], parts[1]];
        if (parts.length > 2) {
          try {
            const decoded = decodeURIComponent(parts[2]);
            normalized.push(decoded);
          } catch (e) {
            normalized.push(parts[2]);
          }
        }
        for (let i = 3; i < parts.length; i++) {
          if (parts[i]) {
            try {
              const decoded = decodeURIComponent(parts[i]);
              normalized.push(encodeURIComponent(decoded));
            } catch (e) {
              normalized.push(encodeURIComponent(parts[i]));
            }
          } else {
            normalized.push(parts[i]);
          }
        }
        variants.push(normalized.join('/'));
        
        // 完全编码版本
        const fullyEncoded = [parts[0], parts[1]];
        for (let i = 2; i < parts.length; i++) {
          if (parts[i]) {
            try {
              const decoded = decodeURIComponent(parts[i]);
              fullyEncoded.push(encodeURIComponent(decoded));
            } catch (e) {
              fullyEncoded.push(encodeURIComponent(parts[i]));
            }
          } else {
            fullyEncoded.push(parts[i]);
          }
        }
        variants.push(fullyEncoded.join('/'));
      }
      
      return variants;
    },

    /** 标准化路径：确保编码一致性 */
    normalizePath(path) {
      const parts = path.split("/");
      if (parts.length < 3) return path;
      
      const normalized = [parts[0]]; // 空字符串
      normalized.push(parts[1]); // 语言段不编码
      
      // menu.en 不编码（第2个段）
      if (parts.length > 2) {
        try {
          const decoded = decodeURIComponent(parts[2]);
          normalized.push(decoded); // menu.en 保持不编码
        } catch (e) {
          normalized.push(parts[2]);
        }
      }
      
      // subMenu.en 和后续段需要编码
      for (let i = 3; i < parts.length; i++) {
        const segment = parts[i];
        if (segment) {
          try {
            const decoded = decodeURIComponent(segment);
            normalized.push(encodeURIComponent(decoded));
          } catch (e) {
            normalized.push(encodeURIComponent(segment));
          }
        } else {
          normalized.push(segment);
        }
      }
      
      return normalized.join("/");
    },

    /** 生成路径的多种可能格式 */
    generatePathAlternatives(path) {
      const alternatives = [path];
      const parts = path.split("/");
      
      if (parts.length >= 3) {
        // 尝试完全编码版本
        const fullyEncoded = [parts[0], parts[1]];
        for (let i = 2; i < parts.length; i++) {
          if (parts[i]) {
            try {
              const decoded = decodeURIComponent(parts[i]);
              fullyEncoded.push(encodeURIComponent(decoded));
            } catch (e) {
              fullyEncoded.push(encodeURIComponent(parts[i]));
            }
          } else {
            fullyEncoded.push(parts[i]);
          }
        }
        alternatives.push(fullyEncoded.join("/"));
      }
      
      return alternatives;
    },

    /** 构建搜索源（按当前语言过滤，抽取有 uri 的条目） */
    loadAll() {
      const langSeg = (this.$route.path.split("/")[1] || "").toLowerCase();
      const all = this.allContent;
      const isZh = langSeg === "zh-tw";

      return Object.keys(all)
        .map(path => {
          const doc = all[path] && all[path].doc;
          if (!doc || !doc.api || !doc.api.uri) {
            return null;
          }

          const value = doc.api.uri;
          // 添加友好的显示标签
          const label = isZh ? (doc.title || value) : (doc.en || value);

          return { path, value, label };
        })
        .filter(
          item =>
            item !== null &&
            item.value &&
            pathIncludesLang(item.path, langSeg)
        );

      function pathIncludesLang(p, seg) {
        return (p.split("/")[1] || "").toLowerCase() === seg;
      }
    },

    querySearchAsync(queryString, cb) {
      const list = this.restaurants;
      if (!queryString) {
        clearTimeout(this.timeout);
        this.timeout = setTimeout(() => cb(list), 100);
        return;
      }

      const query = queryString.toLowerCase();
      const res = list.filter(
        s => {
          const value = (s.value || "").toLowerCase();
          const label = (s.label || "").toLowerCase();
          // 支持按 URI 或标题搜索
          return value.indexOf(query) === 0 || label.indexOf(query) !== -1;
        }
      );

      clearTimeout(this.timeout);
      this.timeout = setTimeout(() => cb(res), 100);
    },

    handleSelect(item) {
      // console.log('Selected menu item:', item);
      this.$router.push(item.path);
    },
    clearSearch() {
      this.searchData = "";
    },
    // 一级菜单 -> 图标名（按你的 menu.en 来映射）
    iconOfTop(menu) {
      for (let i = 0; i < apiDocs.length; i++) {
        if (apiDocs[i] && apiDocs[i].en === menu.en) {
          return apiDocs[i].icon || "doc";
        }
      }
      return "doc";
    },

    // 图标名 -> SVG 字符串（统一风格、currentColor）
    iconSvg(name) {
      const base = `xmlns="http://www.w3.org/2000/svg"
        width="20" height="20" viewBox="0 0 24 24"
        fill="none" stroke="currentColor"
        stroke-width="1.5"
        stroke-linecap="round"
        stroke-linejoin="round"`;

      const icons = {
        home: `<svg ${base}>
          <path d="M4 11L12 4l8 7"/>
          <path d="M6 10v10h12V10"/>
          <path d="M10 20v-6h4v6"/>
          </svg>`,

        quick: `<svg ${base}>
                <path d="M13 2L3 14h7l-1 8 10-12h-7l1-8z"/>
            </svg>`,

        swap: `<svg ${base}>
                <path d="M7 7h11"/>
                <path d="M15 4l3 3-3 3"/>
                <path d="M17 17H6"/>
                <path d="M9 14l-3 3 3 3"/>
              </svg>`,

        spot: `<svg ${base}>
          <circle cx="12" cy="12" r="7"/>
          <path d="M9 13l2-2 2 2 2-3"/>
        </svg>`,
        cswap: `<svg ${base}>
                  <path d="M8 3h8l3 3v14a2 2 0 0 1-2 2H8a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2z"/>
                  <path d="M16 3v4h4"/>
                  <path d="M10 12h4"/>
                  <path d="M10 15l-2 2 2 2"/>
                  <path d="M14 19l2-2-2-2"/>
                </svg>`,

        wallet: `<svg ${base}>
                  <path d="M4 8h16a2 2 0 0 1 2 2v8a2 2 0 0 1-2 2H4a2 2 0 0 1-2-2v-8a2 2 0 0 1 2-2z"/>
                  <path d="M16 12h6"/>
                </svg>`,

        users: `<svg ${base}>
                  <path d="M12 11a3 3 0 1 0 0-6 3 3 0 0 0 0 6z"/>
                  <path d="M5 20a7 7 0 0 1 14 0"/>
                </svg>`,

        copy: `<svg ${base}>
                <rect x="9" y="7" width="11" height="13" rx="2"/>
                <rect x="4" y="4" width="11" height="13" rx="2"/>
              </svg>`,

        refresh: `<svg ${base}>
                    <path d="M20 12a8 8 0 1 1-2.3-5.7"/>
                    <path d="M20 4v6h-6"/>
                  </svg>`
      };

      return icons[name] || icons.doc;
    }
  }
};
</script>



