const paths = require.context('./', true, /\.json$/).keys();
let content = []
for (let i = 0; i < paths.length; i++) {
    const file = require(`${paths[i]}`)
    const tmp = {
        "en": file.en,
        "tittle": file.title,
        "twoLevel": true,
        "docs": [{ doc: file, path: encodeURIComponent(paths[i]), pathOri: paths[i] }]
    }
    content  = content.concat(tmp)

}
export const Data = content


