<template>
  <div>
    <!-- 语言标识，简体中文/英文 -->
    <div v-if="this.$store.state.lang == '繁体中文'">
      <!-- 中文内容显示 -->
      <div v-if="content.type == 'DESCRIPTION'">
        <div v-for="value in content.lines.zh" v-html="value"></div>
      </div>

      <div v-if="content.type == 'CHANGELOGS'">
        <el-table header-height="30px" :data="content.logs.zh" border width="120%" :row-class-name="tableRowClassName">
          <el-table-column prop="updateTime" label="更新時間" width="120"> </el-table-column>
          <el-table-column prop="path" label="接口地址" width="250"> </el-table-column>
          <el-table-column prop="type" label="更新類型" width="120"> </el-table-column>
          <el-table-column prop="info" label="更新摘要" width="350"> </el-table-column>
          <el-table-column prop="model" label="業務" width="250"> </el-table-column>
          <el-table-column label="查看詳情" width="200">
            <template v-slot="scope">
              <el-link v-if="getDocLinkByApiPath(scope.row.path)"  type="primary" :href="getDocLinkByApiPath(scope.row.path)" target="_blank">
                查看詳情
              </el-link>
            </template>
          </el-table-column>
        </el-table>
      </div>

      <div v-if="content.type == 'REST'">
        <restfulApi :content="content" />
      </div>
      <div v-if="content.type == 'WEBSOCKET'">
        <websocketDoc :content="content" />
      </div>
    </div>

    <div v-else>
      <!-- 英文内容显示 -->
      <div v-if="content.type == 'DESCRIPTION'">
        <div v-for="value in content.lines.en" v-html="value"></div>
      </div>

      <div v-if="content.type == 'CHANGELOGS'">
        <el-table header-height="30px" :data="content.logs.en" border width="120%" :row-class-name="tableRowClassName">
          <el-table-column prop="updateTime" label="Update Time" width="120"> </el-table-column>
          <el-table-column prop="path" label="API Path" width="250"> </el-table-column>
          <el-table-column prop="type" label="Update Type" width="120"> </el-table-column>
          <el-table-column prop="info" label="Update Summary" width="350"> </el-table-column>
          <el-table-column prop="model" label="Business" width="250"> </el-table-column>
          <el-table-column label="View Details" width="200">
            <template v-slot="scope">
              <el-link v-if="getDocLinkByApiPath(scope.row.path)"  type="primary" :href="getDocLinkByApiPath(scope.row.path)" target="_blank">
                View Details
              </el-link>
            </template>
          </el-table-column>
        </el-table>
      </div>

      <div v-if="content.type == 'REST'">
        <restfulApi :content="content" />
      </div>
      <div v-if="content.type == 'WEBSOCKET'">
        <websocketDoc :content="content" />
      </div>
    </div>
  </div>
</template>
<style>
.code-html {
    color: #FFFFFF;
    background-color: #282c34;
    overflow: hidden;
}

.code-html pre {
    margin: 0;
    padding: 0;
}


.code-html code {
    height: 60px;
    overflow: auto;
}

.el-table .warning-row {
    background: oldlace;
}

.code-html {
    height: 200px;
    margin: 0;
}

.el-table .success-row {
    background: #f0f9eb;
}

.el-table .el-table__header-wrapper tr {
    height: 20px;
    line-height: 20px;
}

.el-table .el-table__header-wrapper th {
    height: 25px;
    line-height: 25px;
    background-color: #eaedf0;
    color: black;
}


</style>
<script>
import { docs as apiDocs } from '../Docs/index'
import restfulApi from './restfulApi'
import websocketDoc from './websocketDoc'

// 组件外先构建一次索引，避免重复遍历
const enDoc = {}
const cnDoc = {}

apiDocs.forEach(menu => {
  menu.list.forEach(subMenu => {
    const isTwo = subMenu.twoLevel === true && Array.isArray(subMenu.docs) && subMenu.docs.length > 0;
    const entryIndex = Number.isInteger(subMenu.entryIndex) ? subMenu.entryIndex : 0;

    // 对 menu.en 和 subMenu.en 都进行 encodeURIComponent 编码
    const encodedMenuEn = encodeURIComponent(menu.en);
    const encodedSubMenuEn = encodeURIComponent(subMenu.en);

    // 1) twoLevel：把 docs[entryIndex] 直接挂到 <locale>/<menu>/<sub>
    if (isTwo) {
      const docObj = subMenu.docs[entryIndex];
      // 同时存储编码和未编码的版本，以支持不同的访问方式
      const keyZH1 = `/zh-tw/${menu.en}/${encodedSubMenuEn}`;
      const keyZH2 = `/zh-tw/${encodedMenuEn}/${encodedSubMenuEn}`;
      const keyEN1 = `/en/${menu.en}/${encodedSubMenuEn}`;
      const keyEN2 = `/en/${encodedMenuEn}/${encodedSubMenuEn}`;
      cnDoc[keyZH1] = docObj.doc;
      cnDoc[keyZH2] = docObj.doc;
      enDoc[keyEN1] = docObj.doc;
      enDoc[keyEN2] = docObj.doc;
      // 注意：twoLevel 情况下，不再额外生成第三级 key，避免路径歧义
    }

    // 2) 特殊页：概述 / 更新記錄（保持你的原逻辑）
    subMenu.docs.forEach(docObj => {
      if (docObj.pathOri === './概述.json') {
        cnDoc['/zh-tw/info'] = docObj.doc;
        enDoc['/en/info'] = docObj.doc;
      } else if (docObj.pathOri === './更新記錄.json') {
        cnDoc['/zh-tw/changes/logs'] = docObj.doc;
        enDoc['/en/changes/logs'] = docObj.doc;
      } else {
        // 3) 普通情况：继续写入第三级 key
        // （twoLevel 的子菜单不会走到这一步，因为我们已经在上面处理并"跳过"了）
        if (!isTwo) {
          // 同时存储编码和未编码的版本
          const keyZH1 = `/zh-tw/${menu.en}/${encodedSubMenuEn}/${encodeURIComponent(docObj.doc.title)}`;
          const keyZH2 = `/zh-tw/${encodedMenuEn}/${encodedSubMenuEn}/${encodeURIComponent(docObj.doc.title)}`;
          const keyEN1 = `/en/${menu.en}/${encodedSubMenuEn}/${encodeURIComponent(docObj.doc.en)}`;
          const keyEN2 = `/en/${encodedMenuEn}/${encodedSubMenuEn}/${encodeURIComponent(docObj.doc.en)}`;
          cnDoc[keyZH1] = docObj.doc;
          cnDoc[keyZH2] = docObj.doc;
          enDoc[keyEN1] = docObj.doc;
          enDoc[keyEN2] = docObj.doc;
        }
      }
    });
  });
});



export default {
  name: 'MainContent',
  components: {restfulApi, websocketDoc},

  data() {
    return {
      // 本地数据，不依赖 Vuex
      enDoc: {},
      cnDoc: {},
      lang: 'en', // 本组件内部用；模板若用 $store.state.lang 不受影响
      content: {},
      restApiRequest: [],
      restApiResponse: [],
      errorList: [],
      payload: {},
      responseBody: {},
      uri: {},

      tableData: [
        {env: 'PROD', address: 'https://open-api.bingx.com'},
        {env: 'VST', address: 'https://open-api-vst.bingx.com'}
      ]
    }
  },

  mounted() {

    // 注入预构建索引
    this.enDoc = enDoc
    this.cnDoc = cnDoc
    console.log('route.path:', this.$route.path)
    // console.log('doc(zh):', this.cnDoc[this.$route.path])
    // console.log('doc(en):', this.enDoc[this.$route.path])
    // 初次按路径设置内容
    this.applyContentFromRoute()
  },

  watch: {
    '$route'() {
      this.applyContentFromRoute()
    }
  },

  methods: {
    scrollToElement(tab) {
      this.$nextTick(() => {
        const el = this.$refs[tab.label]
        if (el && el.scrollIntoView) el.scrollIntoView({behavior: 'smooth'})
      })
    },

    /** 按当前路由设置文档与 API 数据（纯本地） */
    applyContentFromRoute() {
      let path = this.$route.path
      const seg = (path.split('/')[1] || '').toLowerCase()
      const isZh = seg === 'zh-tw'
      this.lang = isZh ? 'zh-tw' : 'en'

      // 尝试直接查找（索引中已包含编码和未编码的版本）
      let doc = isZh ? this.cnDoc[path] : this.enDoc[path]
      
      // 如果找不到，尝试标准化路径格式：menu.en 不编码，后续段编码
      if (!doc) {
        const pathParts = path.split('/')
        if (pathParts.length >= 3) {
          const attempts = []
          
          // 标准化路径：menu.en 不编码，subMenu.en 和 title 编码
          const normalized = [pathParts[0], pathParts[1]] // 空字符串和语言段
          
          // menu.en 段（索引2）不编码
          // 需要先修复未编码的 & 字符（如 Account%20&%20Wallet）
          if (pathParts.length > 2) {
            let menuEn = pathParts[2]
            // 修复未编码的 & 字符
            if (menuEn.includes('&') && !menuEn.includes('%26')) {
              menuEn = menuEn.replace(/&/g, '%26')
            }
            try {
              const decoded = decodeURIComponent(menuEn)
              normalized.push(decoded) // menu.en 不编码
            } catch (e) {
              normalized.push(pathParts[2])
            }
          }
          
          // 后续段（subMenu.en 和 title）需要编码
          for (let i = 3; i < pathParts.length; i++) {
            const segment = pathParts[i]
            if (segment) {
              try {
                // 先解码（处理Vue Router可能已解码的情况）
                const decoded = decodeURIComponent(segment)
                // 重新编码，确保格式一致
                normalized.push(encodeURIComponent(decoded))
              } catch (e) {
                // 解码失败，说明可能包含未编码字符，直接编码
                normalized.push(encodeURIComponent(segment))
              }
            } else {
              normalized.push(segment)
            }
          }
          attempts.push(normalized.join('/'))
          
          // 完全编码版本（除了语言段）
          const fullyEncoded = [pathParts[0], pathParts[1]]
          for (let i = 2; i < pathParts.length; i++) {
            let segment = pathParts[i]
            if (segment) {
              // 修复未编码的 & 字符
              if (segment.includes('&') && !segment.includes('%26')) {
                segment = segment.replace(/&/g, '%26')
              }
              try {
                const decoded = decodeURIComponent(segment)
                fullyEncoded.push(encodeURIComponent(decoded))
              } catch (e) {
                fullyEncoded.push(encodeURIComponent(segment))
              }
            } else {
              fullyEncoded.push(segment)
            }
          }
          attempts.push(fullyEncoded.join('/'))
          
          // 尝试所有可能的路径格式
          for (const attemptPath of attempts) {
            doc = isZh ? this.cnDoc[attemptPath] : this.enDoc[attemptPath]
            if (doc) {
              console.log('Found doc with path:', attemptPath)
              break
            }
          }
          
          // 如果还是找不到，尝试遍历所有索引键，找到匹配的文档
          if (!doc) {
            const docMap = isZh ? this.cnDoc : this.enDoc
            for (const [indexPath, indexDoc] of Object.entries(docMap)) {
              // 比较路径的各个段（忽略编码差异）
              const currentParts = path.split('/')
              const indexParts = indexPath.split('/')
              
              if (currentParts.length === indexParts.length) {
                let match = true
                for (let i = 0; i < currentParts.length; i++) {
                  if (i === 0) continue // 跳过空字符串
                  if (i === 1) {
                    // 语言段必须完全匹配
                    if (currentParts[i] !== indexParts[i]) {
                      match = false
                      break
                    }
                  } else {
                    // 其他段：解码后比较
                    try {
                      const currentDecoded = decodeURIComponent(currentParts[i].replace(/&/g, '%26'))
                      const indexDecoded = decodeURIComponent(indexParts[i].replace(/&/g, '%26'))
                      if (currentDecoded !== indexDecoded) {
                        match = false
                        break
                      }
                    } catch (e) {
                      // 如果解码失败，直接比较
                      if (currentParts[i] !== indexParts[i]) {
                        match = false
                        break
                      }
                    }
                  }
                }
                if (match) {
                  doc = indexDoc
                  console.log('Found doc by path matching:', indexPath)
                  break
                }
              }
            }
          }
        }
      }
      
      if (doc) {
        this.content = doc;

        const api = (doc && doc.api) ? doc.api : {};

        this.restApiRequest  = (api.request && Array.isArray(api.request.list)) ? api.request.list : [];
        this.restApiResponse = (api.response && Array.isArray(api.response.list)) ? api.response.list : [];
        this.errorList       = (api.error && Array.isArray(api.error.list)) ? api.error.list : [];
        this.payload         = api.payload || {};
        this.responseBody    = api.responseBody || {};
        this.uri             = api.uri || {};
      } else {
        console.warn('Document not found for path:', this.$route.path)
        this.resetApiData()
        // 设置一个默认的 content 对象，避免白屏
        this.content = {
          type: 'DESCRIPTION',
          lines: {
            zh: ['<p>文档未找到，请检查路径是否正确。</p>'],
            en: ['<p>Document not found. Please check if the path is correct.</p>']
          }
        }
      }
    },

    resetApiData() {
      this.restApiRequest = []
      this.restApiResponse = []
      this.errorList = []
      this.payload = {}
      this.responseBody = {}
      this.uri = {}
    },

    /** 根据API路径查找对应的文档链接 */
    getDocLinkByApiPath(apiPath) {
      if (!apiPath || apiPath === '-' || apiPath.trim() === '') {
        return null;
      }
      
      const normalizedPath = apiPath.trim();
      const currentLang = this.$store.state.lang === '繁体中文' ? 'zh-tw' : 'en';
      const docMap = currentLang === 'zh-tw' ? this.cnDoc : this.enDoc;
      
      // 在所有文档中搜索匹配的API路径
      const matchedPaths = [];
      for (const [docPath, doc] of Object.entries(docMap)) {
        if (doc && doc.api && doc.api.uri) {
          const docApiPath = doc.api.uri.trim();
          if (docApiPath === normalizedPath || docApiPath.toLowerCase() === normalizedPath.toLowerCase()) {
            matchedPaths.push(docPath);
          }
        }
      }
      
      if (matchedPaths.length > 0) {
        // 优先选择标准化路径（menu.en 不编码的版本），与索引构建逻辑一致
        let selectedPath = matchedPaths[0];
        for (const path of matchedPaths) {
          const parts = path.split('/');
          if (parts.length >= 3) {
            // 检查 menu.en 段是否未编码（标准化格式）
            try {
              const decoded = decodeURIComponent(parts[2]);
              if (decoded === parts[2]) {
                // 未编码，是标准化路径
                selectedPath = path;
                break;
              }
            } catch (e) {
              // 解码失败，继续
            }
          }
        }
        return `#${selectedPath}`;
      }
      
      return null;
    }
  }
}
</script>




